import jibo = require('jibo');
import path = require('path');
import BaseTest from '../BaseTest';
import Common from '../Common';
import $ from '../utils/querySelector';

const audioContext = new AudioContext();
let buffer = null;

/**
 * Audio diagnostic test
 */
class AudioTest extends BaseTest {

    public bufferSource:any;

    constructor() {
        super();

        this.bufferSource = null;
        const request = new XMLHttpRequest();
        const url = jibo.utils.PathUtils.getAssetUri('audio/FX_Bleep.mp3');
        request.open('GET', url, true);
        request.responseType = 'arraybuffer';

        request.onload = () => {

            // Decode asynchronously
            audioContext.decodeAudioData(request.response, (_buffer) => {
                buffer = _buffer;
            }, (error?) => {
                throw new Error('Error loading sound file: ' + url);
            });
        }
        request.send();
    }

    enter() {
        Common.log('enter audio');

        Common.centerRobot();
        $('#test-label').innerHTML = 'Click to play';
    }

    exit() {
        Common.log('exit audio');
        this._stop();
        $('#test-label').innerHTML = '';
    }

    click() {
        Common.log('clicked for audio');
        this._stop();
        this._play();
    }

    _stop(){
        if (!this.bufferSource) {
            return;
        }

        this.bufferSource.disconnect();
        this.bufferSource = null;
    }

    _play(){
        if (!buffer) {
            Common.log('Audio buffer not loaded yet...')
            return;
        }

        this.bufferSource = audioContext.createBufferSource();

        // Tell the source which sound to play
        this.bufferSource.buffer = buffer;

        // Connect the source to the context's destination (the speakers)
        this.bufferSource.connect(audioContext.destination);

        // play the source now
        this.bufferSource.start(0);
    }
}

export default AudioTest;