import BaseTest from '../BaseTest';
import Common from '../Common';
import {tts} from 'jibo';
import $ from '../utils/querySelector';

/*
* TTS diagnostic test
* */
class TTSTest extends BaseTest {

    constructor() {
        super();
    }

    enter() {
        Common.centerRobot();

        Common.log('enter tts');
        tts.speak('Hello, my name is Jibo', function(error) {
            if (error) {
                $('#test-label').innerHTML = error;
            }
        });
        tts.on('word', function(word) {
            $('#test-label').innerHTML = word.token;
        })

    }

    exit() {
        Common.log('exit tts');
        $('#test-label').innerHTML = '';

        tts.removeAllListeners();
    }
}

export default TTSTest;
