import BaseTest from '../BaseTest';
import Common from '../Common';
import $ from '../utils/querySelector';

/*
* No diagnostic test
* */
class WebGLTest extends BaseTest {

    constructor() {
        super();
    }

    enter() {
        Common.log('enter webgl test');
        Common.centerRobot();

        const webDiv = $('#webgl');
        webDiv.src = 'http://webglreport.com/?v=1';
        webDiv.style.display = 'block';
    }

    exit() {
        Common.log('exit webgl test');

        const webDiv = $('#webgl');
        webDiv.src = '';
        webDiv.style.display = 'none';
    }
}

export default WebGLTest;
