import BaseTest from '../BaseTest';
import jibo = require('jibo');
import path = require('path');
import Common from '../Common';
import $ from '../utils/querySelector';

let animInstance = undefined;
/*
* LED diagnostic test
* */
class LEDTest extends BaseTest {

    public animutils:any;
    public animPath:string;
    public exiting:boolean;

    constructor() {
        super();

        this.animutils = (jibo.animate as any).createAnimationUtilities();
        // this.animutils.blink();
        this.animPath = jibo.utils.PathUtils.getAssetUri('animations/led.keys');
        this.exiting = false;
    }

    enter() {
        Common.log('enter LED');
        Common.centerRobot();

        $('#test-label').innerHTML = 'Pretty colors';
        this.exiting = false;
        this._exitHelper();

        const builder = this.animutils.createAnimationBuilderFromKeysPath(this.animPath, '.', (builder) => {
            builder.on('STOPPED', () => {
                if (!this.exiting) {
                    animInstance = builder.play(); // loop if we are not exiting test
                }
            });
            builder.setTransitionIn(null);
            animInstance = builder.play();
        });
    }

    exit() {
        $('#test-label').innerHTML = '';
        Common.log('exit LED');
        this.exiting = true;
        this._exitHelper();
    }

    _exitHelper() {
        if (animInstance) {
            animInstance.stop();
            animInstance = undefined;
            Common.resetLED();
        }
    }
}

export default LEDTest;
