import BaseTest from '../BaseTest';
import jibo = require('jibo');
import Common from '../Common';
import $ from '../utils/querySelector';

const lifecycle = require('../behaviors/lifecycle');

const Status = jibo.bt.Status;

/*
 * Life Cycle diagnostic test
 * */
class LifeCycleTest extends BaseTest {

    public exiting:boolean;
    public root:any;
    public cyclesSoFar:number;
    public looping:boolean;
    public dirty:boolean;

    constructor() {
        super();

        this.root = jibo.bt.create(lifecycle);

        this.exiting = false;
        this.cyclesSoFar = 0;
        this.looping = true; // on by default
        this.dirty = false;
    }

    enter() {
        Common.log('entering lifecycle test');
        this._startCycle();
    }

    _startCycle() {
        // start behavior & set appropriate flags

        // 1. say random greeting...
        const phrases = [
            'What\'s up',
            'Yo',
            'Howdy',
            'Hi ya',
            'Greetings',
            'Hello',
            'Dude, that\'s rad',
            'Sup bro',
            'Hey guys and gals',
            'Danger! Danger, Will Robinson!'
        ];

        const randomInt = Math.floor(Math.random() * phrases.length);
        const phrase = phrases[randomInt];
        jibo.tts.speak(phrase, function(err) {
            // What to do when service is down? Just ignore, or switch
            // here to chrome's implementation if we're not running on the robot
            if(err){
                Common.error('tts.speak() error: ' + err);
            }
        });

        // 2. start behavior
        this.root.start();

        // 3. dirty for render update
        this.dirty = true;
    }


    exit() {
        Common.log('exit lifecycle test');
        $('#test-label').innerHTML = '';
        $('#test-label2').innerHTML = '';
        $('#test-label3').innerHTML = '';

        this.exiting = true;
        this._exitHelper();
    }

    _exitHelper() {
        if (this.root) {
            this.root.stop();
            this.root = undefined;
        }

        Common.resetLED();
    }

    click() {
        this.looping = !this.looping; // toggle looping
        this.dirty = true;
    }

    update() {
        if (this.exiting) {
            return;
        }

        this.root.update();

        if (this.root.currentStatus === Status.SUCCEEDED) {
            // one cycle is over, so pause it
            this.root.pause();
            this.cyclesSoFar++;
            this.dirty = true;
        }

        // check if we need to start it again
        if (this.looping && (this.root.currentStatus === Status.PAUSED)) {
            this._startCycle();
        }

        // update text if needed
        if (this.dirty) {
            $('#test-label').innerHTML = (this.looping ? 'Looping (tap to toggle)' : 'Not looping (tap to toggle)');
            $('#test-label2').innerHTML = 'cycles completed: ' + this.cyclesSoFar;

            this.dirty = false;
        }
    }
}

export default LifeCycleTest;
