import BaseTest from '../BaseTest';
import jibo = require('jibo');
import Common from '../Common';
import $ from '../utils/querySelector';

const tracking = require('../behaviors/tracking');

/*
* LPS tracking diagnostic test
* */
class TrackingTest extends BaseTest {

    public root:any;

    constructor() {
        super();
        this.root = jibo.bt.create(tracking);
    }

    enter() {
        Common.centerRobot();
        Common.log('enter tracking');
        $('#test-label').innerHTML = 'Look at me!';
        this.root.start();
    }

    exit() {
        Common.log('exit tracking');
        $('#test-label').innerHTML = '';
        this.root.stop();
    }

    update() {
        this.root.update();
    }
}

export default TrackingTest;
